```class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int n = s.size(), res = 0;
        for (int i = 0; i < n; ++i) {
            int cnt = 1, j = i + 1;
            while (j < n && s[j] != s[j - 1]) ++j, ++cnt;
            res = max(res, cnt);
            while (j < n && s[j] == s[j - 1]) ++j;
            if (j < n) {
                cnt = 1;
                while (j < n && s[j] != s[j - 1]) ++j, ++cnt;
                res = max(res, cnt);
            }
        }
        return res;
    }
};
